import{_ as t,a,b as o,c as d,d as r,e as p}from"./chunks/查询额度成功.BKueuYqe.js";import{_ as s,o as n,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"د Dropbox Channel اضافه کول","description":"","frontmatter":{},"headers":[],"relativePath":"ps/upload/dropbox.md","filePath":"ps/upload/dropbox.md","lastUpdated":1781962217000}'),c={name:"ps/upload/dropbox.md"};function h(b,e,u,m,x,g){return n(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="د-dropbox-channel-اضافه-کول" tabindex="-1">د Dropbox Channel اضافه کول <a class="header-anchor" href="#د-dropbox-channel-اضافه-کول" aria-label="Permalink to &quot;د Dropbox Channel اضافه کول&quot;">​</a></h1><h2 id="مخکې-څه-ته-اړتیا-لرئ" tabindex="-1">مخکې څه ته اړتیا لرئ <a class="header-anchor" href="#مخکې-څه-ته-اړتیا-لرئ" aria-label="Permalink to &quot;مخکې څه ته اړتیا لرئ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>اړتیا</th><th>ولې ورته اړتیا ده</th></tr></thead><tbody><tr><td>Dropbox account</td><td>sign in او app authorize کولو لپاره</td></tr><tr><td>Dropbox app</td><td>د <code>App Key</code> او <code>App Secret</code> جوړولو لپاره</td></tr><tr><td>ستاسو ImgBed domain</td><td>د OAuth redirect URI لپاره</td></tr><tr><td>کافي Dropbox storage</td><td>د فایلونو اصلي storage ځای</td></tr></tbody></table><h2 id="د-تنظیم-پړاوونه" tabindex="-1">د تنظیم پړاوونه <a class="header-anchor" href="#د-تنظیم-پړاوونه" aria-label="Permalink to &quot;د تنظیم پړاوونه&quot;">​</a></h2><h3 id="_1-ګام-dropbox-app-جوړ-کړئ" tabindex="-1">1 ګام: Dropbox App جوړ کړئ <a class="header-anchor" href="#_1-ګام-dropbox-app-جوړ-کړئ" aria-label="Permalink to &quot;1 ګام: Dropbox App جوړ کړئ&quot;">​</a></h3><ol><li>د Dropbox App Console پرانیزئ:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.dropbox.com/developers/apps</span></span></code></pre></div><ol start="2"><li>نوی app جوړ کړئ.</li><li>د access type لپاره دا وټاکئ:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App folder</span></span></code></pre></div><ol start="4"><li>app ته داسې نوم ورکړئ چې وپېژندل شي، لکه <code>imgbed-app</code>.</li><li>له جوړېدو وروسته د app details پاڼه پرانیزئ.</li></ol><p>سپارښت شوی access type:</p><table tabindex="0"><thead><tr><th>Access Type</th><th>سپارښتنه</th></tr></thead><tbody><tr><td><code>App folder</code></td><td>سپارښتنه کېږي. دا د ImgBed د فایل ساتلو له طریقې سره ښه برابر دی.</td></tr><tr><td><code>Full Dropbox</code></td><td>نه سپارښتل کېږي. ImgBed د ټول account access ته اړتیا نه لري.</td></tr></tbody></table><p><img src="'+t+'" alt="Create Dropbox app" loading="lazy"></p><h3 id="_2-ګام-redirect-uri-اضافه-کړئ" tabindex="-1">2 ګام: Redirect URI اضافه کړئ <a class="header-anchor" href="#_2-ګام-redirect-uri-اضافه-کړئ" aria-label="Permalink to &quot;2 ګام: Redirect URI اضافه کړئ&quot;">​</a></h3><p>د Dropbox app details پاڼه کې د OAuth یا Redirect URI settings ومومئ او دا اضافه کړئ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/dropbox/callback</span></span></code></pre></div><p>که admin panel له څو domainونو کاروئ، د هر domain لپاره ورته callback URL اضافه کړئ.</p><p><img src="'+a+'" alt="Configure redirect URI" loading="lazy"></p><h3 id="_3-ګام-app-permissions-تنظیم-کړئ" tabindex="-1">3 ګام: App Permissions تنظیم کړئ <a class="header-anchor" href="#_3-ګام-app-permissions-تنظیم-کړئ" aria-label="Permalink to &quot;3 ګام: App Permissions تنظیم کړئ&quot;">​</a></h3><p><code>Permissions</code> tab پرانیزئ او لږ تر لږه دا scopes فعال کړئ:</p><table tabindex="0"><thead><tr><th>Scope</th><th>Required</th><th>موخه</th></tr></thead><tbody><tr><td><code>account_info.read</code></td><td>Required</td><td>د account او quota معلومات لولي</td></tr><tr><td><code>files.metadata.read</code></td><td>Required</td><td>د path check لپاره د فایل او folder metadata لولي</td></tr><tr><td><code>files.metadata.write</code></td><td>Required</td><td>folders جوړوي او metadata لیکي</td></tr><tr><td><code>files.content.write</code></td><td>Required</td><td>فایلونه upload کوي. که دا scope نه وي، <code>required scope &#39;files.content.write&#39;</code> خطا راځي.</td></tr><tr><td><code>files.content.read</code></td><td>Recommended</td><td>download، preview او temporary file links ته اجازه ورکوي</td></tr></tbody></table><p>له scope ټاکلو وروسته د پاڼې په پای کې <code>Submit</code> کلیک کړئ.</p><p><img src="'+o+'" alt="Add permissions" loading="lazy"></p><p>مهم:</p><table tabindex="0"><thead><tr><th>حالت</th><th>څه وکړئ</th></tr></thead><tbody><tr><td>scopes مو بدل کړل</td><td>token authorization flow بیا اجرا کړئ او نوی <code>Refresh Token</code> واخلئ.</td></tr><tr><td>بیا مو authorize نه کړل</td><td>زوړ token نوې permissions نه اخلي، نو upload ښايي لا هم ناکام شي.</td></tr></tbody></table><h3 id="_4-ګام-app-credentials-copy-کړئ" tabindex="-1">4 ګام: App Credentials copy کړئ <a class="header-anchor" href="#_4-ګام-app-credentials-copy-کړئ" aria-label="Permalink to &quot;4 ګام: App Credentials copy کړئ&quot;">​</a></h3><p>له Dropbox app page څخه دا دوه ارزښتونه وساتئ:</p><table tabindex="0"><thead><tr><th>Dropbox Field</th><th>ImgBed Field</th></tr></thead><tbody><tr><td><code>App key</code></td><td><code>App Key</code></td></tr><tr><td><code>App secret</code></td><td><code>App Secret</code></td></tr></tbody></table><h3 id="_5-ګام-د-dropbox-channel-ډک-کړئ" tabindex="-1">5 ګام: د Dropbox Channel ډک کړئ <a class="header-anchor" href="#_5-ګام-د-dropbox-channel-ډک-کړئ" aria-label="Permalink to &quot;5 ګام: د Dropbox Channel ډک کړئ&quot;">​</a></h3><p>په Upload Settings کې <code>Dropbox</code> وټاکئ او دا fields ډک کړئ:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>څه ولیکئ</th></tr></thead><tbody><tr><td>Channel name</td><td>داسې نوم چې وپېژندل شي، لکه <code>Main Dropbox</code></td></tr><tr><td>App Key</td><td>د Dropbox <code>App key</code></td></tr><tr><td>App Secret</td><td>د Dropbox <code>App secret</code></td></tr><tr><td>Refresh Token</td><td>اوس یې تش پرېږدئ</td></tr><tr><td>Root directory</td><td>اختیاري. Default یې <code>imgbed</code> دی.</td></tr><tr><td>Note</td><td>اختیاري</td></tr></tbody></table><p><img src="'+d+'" alt="Get token" loading="lazy"></p><h3 id="_6-ګام-refresh-token-واخلئ" tabindex="-1">6 ګام: Refresh Token واخلئ <a class="header-anchor" href="#_6-ګام-refresh-token-واخلئ" aria-label="Permalink to &quot;6 ګام: Refresh Token واخلئ&quot;">​</a></h3><ol><li>په ImgBed کې <code>Get Token</code> کلیک کړئ.</li><li>هغه Dropbox account ته sign in وکړئ چې نښلول یې غواړئ.</li><li>د authorization غوښتنه approve کړئ.</li><li>callback page به <code>Refresh Token</code> ښکاره کړي.</li><li>هغه copy کړئ.</li><li>بېرته ImgBed ته راشئ او د <code>Refresh Token</code> field کې یې paste کړئ.</li></ol><p><img src="'+r+'" alt="Copy token" loading="lazy"></p><h2 id="څنګه-یې-verify-کړئ" tabindex="-1">څنګه یې verify کړئ <a class="header-anchor" href="#څنګه-یې-verify-کړئ" aria-label="Permalink to &quot;څنګه یې verify کړئ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Expected Result</th></tr></thead><tbody><tr><td>Channel card</td><td>د save وروسته Dropbox channel ښکاره کېږي.</td></tr><tr><td>Channel switch</td><td>channel فعالېدای شي.</td></tr><tr><td>Token saved</td><td>detail page ښيي چې <code>Refresh Token</code> خوندي شوی دی.</td></tr><tr><td>Upload test</td><td>test image د Dropbox app folder کې ښکاري.</td></tr></tbody></table><p>که quota limits فعال وي، quota query کلیک کړئ. له بریالۍ query وروسته channel card used space، total space او last update time ښيي.</p><p><img src="'+p+`" alt="Quota query success" loading="lazy"></p><h2 id="ستونزې-او-حل" tabindex="-1">ستونزې او حل <a class="header-anchor" href="#ستونزې-او-حل" aria-label="Permalink to &quot;ستونزې او حل&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ستونزه</th><th>حل</th></tr></thead><tbody><tr><td>ImgBed وايي configuration نیمګړی دی</td><td>وګورئ چې <code>App Key</code>، <code>App Secret</code> او <code>Refresh Token</code> ټول ډک دي.</td></tr><tr><td>Authorization بریالی کېږي خو <code>Refresh Token</code> نه ښکاري</td><td><code>Get Token</code> بیا کلیک کړئ او ډاډه شئ چې offline authorization flow کارېږي.</td></tr><tr><td>Upload د <code>required scope &#39;files.content.write&#39;</code> سره ناکامېږي</td><td><code>files.content.write</code> فعال کړئ، <code>Submit</code> کلیک کړئ، بیا نوی <code>Refresh Token</code> واخلئ.</td></tr><tr><td>Callback ناکامېږي</td><td>ډاډ ترلاسه کړئ چې redirect URI دا دی: <code>https://your-domain.com/api/oauth/dropbox/callback</code>.</td></tr><tr><td>فایلونه نه موندل کېږي</td><td>وګورئ Dropbox app په <code>App folder</code> mode کې جوړ شوی دی.</td></tr></tbody></table><h2 id="چټک-بهیر" tabindex="-1">چټک بهیر <a class="header-anchor" href="#چټک-بهیر" aria-label="Permalink to &quot;چټک بهیر&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Open Dropbox App Console</span></span>
<span class="line"><span>-&gt; Create an app</span></span>
<span class="line"><span>-&gt; Choose App folder access</span></span>
<span class="line"><span>-&gt; Add https://your-domain.com/api/oauth/dropbox/callback</span></span>
<span class="line"><span>-&gt; Enable account_info.read / files.metadata.read / files.metadata.write / files.content.write</span></span>
<span class="line"><span>-&gt; Optionally enable files.content.read</span></span>
<span class="line"><span>-&gt; Click Submit</span></span>
<span class="line"><span>-&gt; Copy App Key and App Secret</span></span>
<span class="line"><span>-&gt; Fill them into ImgBed</span></span>
<span class="line"><span>-&gt; Click Get Token</span></span>
<span class="line"><span>-&gt; Copy the Refresh Token from the callback page</span></span>
<span class="line"><span>-&gt; Paste it back into ImgBed and save</span></span></code></pre></div><h2 id="ماخذونه" tabindex="-1">ماخذونه <a class="header-anchor" href="#ماخذونه" aria-label="Permalink to &quot;ماخذونه&quot;">​</a></h2><ol><li>Dropbox App Console: <a href="https://www.dropbox.com/developers/apps" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/apps</a></li><li>Dropbox OAuth Guide: <a href="https://developers.dropbox.com/oauth-guide" target="_blank" rel="noreferrer">https://developers.dropbox.com/oauth-guide</a></li><li>Dropbox Developer Guide: <a href="https://www.dropbox.com/developers/reference/developer-guide" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/reference/developer-guide</a></li></ol>`,45)])])}const _=s(c,[["render",h]]);export{y as __pageData,_ as default};
